-- Expand: add new column without constraints
ALTER TABLE conversation_logs ADD COLUMN model_version_v2 TEXT;
-- Zero-downtime: no lock required for nullable ADD COLUMN in PostgreSQL 11+

-- Rollback: stop dual-writes (application code change) then:
ALTER TABLE conversation_logs DROP COLUMN model_version_v2;
-- Safe: old column is still authoritative; no data loss

-- Contract: only run after old column reads have been fully removed from code
ALTER TABLE conversation_logs DROP COLUMN model_version;
-- After this: rollback requires snapshot restore
